(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[2560],{1016:(e,t,o)=>{"use strict";o.r(t),o.d(t,{data:()=>a});const a={key:"v-2adf96de",path:"/python/loop/",title:"ลูป",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"python/loop/README.md",git:{updatedTime:162676698e4,contributors:[]}}},4309:(e,t,o)=>{"use strict";o.r(t),o.d(t,{default:()=>d});const a=(0,o(6252).uE)('<h1 id="ลูป" tabindex="-1"><a class="header-anchor" href="#ลูป" aria-hidden="true">#</a> ลูป</h1><p>Loop หรือ Iteration หรือที่ภาษาไทยที่เรียกว่า &quot;วน&quot; หรือการทำซ้ำ<br> โดยการวนของ Python ก็จะมีอยู่ 2 ประเภทตามที่น้องๆต้องการใข้งาน</p><ol><li>วนเมื่อเงื่อนไขถูกต้อง (Condition-based Loop) หรือในการใช้งานแบบ <code>WHILE</code> นั่นเอง</li><li>วนตามจำนวนที่ได้ระบุไว้ (Amount-based Loop) หรือในการใช้งานแบบ <code>FOR</code> นั่นเอง</li></ol><p>โดยน้องๆควรเลือกประเภทการวนให้เป็นไปตามที่มันควรจะเป็นนะครับ วิจารณญาณล้วนๆ</p>',4),d={render:function(e,t){return a}}}}]);